SELECT "ResoCarico" AS TipoMovimento, [Transfer Shipment Header].No_ AS NoDocumento, [Transfer Shipment Header].[Posting Date] AS DataVendita, EANCodes.[Cross-Reference No_] AS EANCode, -Val([quantity]) AS quantita, [Transfer Shipment Line].[Model Item No_] AS Articolo, [Transfer Shipment Line].[Variable Code 01] AS Colore, [Transfer Shipment Line].[Variable Code 02] AS Taglia, Item.[Trademark Code] AS Marchio, Item.[Season Code] AS Stagione
FROM (([Transfer Shipment Header] INNER JOIN [Transfer Shipment Line] ON [Transfer Shipment Header].No_ = [Transfer Shipment Line].[Document No_]) LEFT JOIN EANCodes ON [Transfer Shipment Line].[Item No_] = EANCodes.[Item No_]) INNER JOIN Item ON [Transfer Shipment Line].[Item No_] = Item.No_
WHERE ((([Transfer Shipment Header].No_)=[Forms]![Principale]![FiltroOdtPerNegozioOutlet]) AND (([Transfer Shipment Line].[Item Type])=0) AND ((Item.[advertising material])=0) AND (([Transfer Shipment Header].[Transfer-from Code])="VENEZIA" Or ([Transfer Shipment Header].[Transfer-from Code])="VENEZIA 2"));

